parameters.jsCode:
const input = $input.item.json;
const remetente = $('ProcessaMensagem').first().json.remetente;
const buscaOriginal = $('ProcessaMensagem').first().json.busca_limpa;
const camposAcumulados = $('ProcessaMensagem').first().json.campos_acumulados || {};

const staticData = $getWorkflowStaticData('global');
if (!staticData.contextos) staticData.contextos = {};

// Se busca_limpa é "refinar", ignora o Groq e usa só campos acumulados
let camposNovos = {};
if (buscaOriginal !== "refinar") {
  try {
    const texto = input.choices[0].message.content.trim();
    camposNovos = JSON.parse(texto.replace(/```json|```/g, "").trim());
  } catch(e) {
    camposNovos = { nome: buscaOriginal };
  }
}

// Mescla campos — novos complementam os existentes
// Campos "QUALQUER" nao sao sobrescritos pelo Groq
const campos = { ...camposAcumulados };
Object.keys(camposNovos).forEach(key => {
  if (campos[key] === "QUALQUER") return;
  if (key === 'nome' && campos.nome && camposNovos.nome && campos.nome !== "QUALQUER") {
    if (!campos.nome.includes(camposNovos.nome)) campos.nome = campos.nome + " " + camposNovos.nome;
  } else {
    campos[key] = camposNovos[key];
  }
});

if (staticData.contextos[remetente]) {
  staticData.contextos[remetente].campos_acumulados = campos;
} else {
  staticData.contextos[remetente] = { campos_acumulados: campos };
}

function removerAcentos(str) {
  if (!str) return "";
  return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase().trim();
}

function montarPattern(str) {
  if (!str || str === "QUALQUER") return null;
  const palavras = removerAcentos(str).toUpperCase().split(/\s+/).filter(function(w){ return w.length >= 3; });
  if (palavras.length === 0) return null;
  const palavrasUsadas = palavras.slice(0, 2);
  // Palavras longas (7+ chars): usar 6 chars para mais precisao
  // Palavras curtas: usar 4 chars
  return "%" + palavrasUsadas.map(function(w){
    var tam = w.length >= 7 ? 6 : 4;
    return w.substring(0, tam);
  }).join("%") + "%";
}

const busca_codigo = campos.codigo || "";
const busca_nome_p = montarPattern(campos.nome);
const busca_municipio_p = montarPattern(campos.municipio);
const busca_orgao_p = montarPattern(campos.orgao);
const busca_situacao_p = montarPattern(campos.situacao);
const busca_tipo_p = montarPattern(campos.tipo);

// Monta WHERE
let where;

if (busca_codigo) {
  where = "TRIM(TO_CHAR(VIP.NUMERO))||'-'||TRIM(TO_CHAR(VIP.ANO)) = '" + busca_codigo.replace("/", "-") + "'";
} else if (busca_nome_p && busca_municipio_p) {
  where = "UPPER(VIP.NOME) LIKE '" + busca_nome_p + "' AND UPPER(M.MUNICIPIO) LIKE '" + busca_municipio_p + "'";
} else if (busca_nome_p) {
  where = "UPPER(VIP.NOME) LIKE '" + busca_nome_p + "'";
} else if (busca_municipio_p) {
  where = "UPPER(M.MUNICIPIO) LIKE '" + busca_municipio_p + "'";
} else {
  where = "1=1";
}

// Filtros adicionais sempre como AND
let whereExtra = "";
if (busca_situacao_p) whereExtra += " AND UPPER(VIP.SITUACAO) LIKE '" + busca_situacao_p + "'";
if (busca_tipo_p) whereExtra += " AND UPPER(VIP.TIPO) LIKE '" + busca_tipo_p + "'";
if (busca_orgao_p) whereExtra += " AND UPPER(VIP.ORGAO) LIKE '" + busca_orgao_p + "'";

const sql = "SELECT DISTINCT VIP.PROJETO_ID, VIP.NUMERO, VIP.ANO, TRIM(TO_CHAR(VIP.NUMERO))||'-'||TRIM(TO_CHAR(VIP.ANO)) AS CODIGO_PROCESSO, VIP.NOME, VIP.SITUACAO, VIP.SITUACAO_ATUAL, VIP.ORGAO, VIP.TIPO, TO_CHAR(VIP.DATAINICIO, 'DD-MM-YYYY') AS DATA_INICIO, TO_CHAR(VIP.DATAFIM, 'DD-MM-YYYY') AS DATA_FIM, VIP.PRAZO_ESTIMADO AS PRAZOESTIMADO, VIP.VALORPLANEJADO, VIP.PERCEXECUTADOFINANC AS PERCENTUAL_EXEC, M.MUNICIPIO, MR.REGIAO FROM VW_IDENTIFICACAO_PROJETOS VIP LEFT JOIN LOCALIZACAO L ON L.PROJETO_ID = VIP.PROJETO_ID LEFT JOIN MUNICIPIO M ON M.ID = L.MUNICIPIO_ID LEFT JOIN MUNICIPIO_REGIAO MR ON MR.MUNICIPIO_ID = M.ID LEFT JOIN PORTFOLIO_PROJETO PP ON VIP.PROJETO_ID = PP.PROJETO_ID LEFT JOIN PORTFOLIO PORT ON PP.PORTFOLIO_ID = PORT.ID LEFT JOIN PROGRAMA_INVESTIMENTO PI ON PI.ID = PP.PROGRAMA_INVESTIMENTO_ID WHERE (" + where + ")" + whereExtra + " ORDER BY VIP.ANO DESC, VIP.NUMERO DESC FETCH FIRST 20 ROWS ONLY";

const busca_limpa_completa = [campos.nome, campos.municipio, campos.situacao, campos.tipo, campos.orgao, campos.codigo]
  .filter(v => v && v !== "QUALQUER")
  .join(" ");

return [{
  remetente,
  busca_limpa: busca_limpa_completa || buscaOriginal,
  campos,
  sql_query: sql
}];

const todos = $input.all();
const remetente = $('ProcessaMensagem').first().json.remetente;
const staticData = $getWorkflowStaticData('global');
const contexto = staticData.contextos?.[remetente] || {};
const p = contexto.projeto_atual || {};

if (todos.length === 0) {
  return [{
    remetente,
    mensagem_retorno:
      "\u274C Nao encontrei entregas para este projeto.\n\n" +
      "Deseja mais informacoes?\n" +
      "1\uFE0F\u20E3 Ver Valores\n" +
      "2\uFE0F\u20E3 Ver Contratos\n" +
      "4\uFE0F\u20E3 Nova Busca"
  }];
}

const linhas = todos.map(item => {
  const e = item.json;
  const perc = e.PERC_EXECUTADO !== null ? " (" + e.PERC_EXECUTADO + "%)" : "";
  return "- " + (e.NOME_ENTREGA || "-") + perc;
}).join("\n");

return [{
  remetente,
  mensagem_retorno:
    "\uD83D\uDCCB Principais Entregas\n" +
    p.CODIGO_PROCESSO + " - " + p.NOME + "\n\n" +
    linhas + "\n\n" +
    "Deseja mais informacoes?\n" +
    "2\uFE0F\u20E3 Ver Valores\n" +
    "3\uFE0F\u20E3 Ver Contratos\n" +
    "4\uFE0F\u20E3 Nova Busca"
}];

const todos = $input.all();
const remetente = $('ProcessaMensagem').first().json.remetente;
const staticData = $getWorkflowStaticData('global');
const contexto = staticData.contextos?.[remetente] || {};
const p = contexto.projeto_atual || {};

if (todos.length === 0) {
  return [{
    remetente,
    mensagem_retorno:
      "\u274C Nao encontrei valores para este projeto.\n\n" +
      "*Deseja mais informacoes?*\n" +
      "1\uFE0F\u20E3 Ver Entregas\n" +
      "3\uFE0F\u20E3 Ver Contratos\n" +
      "4\uFE0F\u20E3 Nova Busca"
  }];
}

function formatarValor(val) {
  const n = parseFloat(String(val || "0").replace(",", ".")) || 0;
  return "R$ " + n.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

const v = todos[0].json;

return [{
  remetente,
  mensagem_retorno:
    "\uD83D\uDCB0 *Valores do Projeto*\n" +
    "*" + p.CODIGO_PROCESSO + " - " + p.NOME + "*\n\n" +
    "\uD83D\uDCB3 *Planejado:* " + formatarValor(v.VALOR_PLANEJADO) + "\n" +
    "\uD83D\uDCB3 *Contratado:* " + formatarValor(v.VALOR_CONTRATADO) + "\n" +
    "\uD83D\uDCB3 *Executado:* " + formatarValor(v.VALOR_EXECUTADO) + "\n" +
    "\uD83D\uDCB3 *Pago:* " + formatarValor(v.VALOR_PAGO) + "\n" +
    "\uD83D\uDCCA *Execucao:* " + (v.PERC_EXEC || "0") + "%\n\n" +
    "*Deseja mais informacoes?*\n" +
    "1\uFE0F\u20E3 Ver Entregas\n" +
    "3\uFE0F\u20E3 Ver Contratos\n" +
    "4\uFE0F\u20E3 Nova Busca"
}];

const todos = $input.all().filter(item => {
  if (!item.json) return false;
  const vals = Object.values(item.json);
  return vals.some(v => v !== null && v !== undefined && v !== "");
});

const remetente = $('ProcessaMensagem').first().json.remetente;
const staticData = $getWorkflowStaticData('global');
const contexto = staticData.contextos?.[remetente] || {};
const p = contexto.projeto_atual || {};

if (todos.length === 0) {
  return [{
    remetente,
    mensagem_retorno:
      "\u274C Nao encontrei contratos para este projeto.\n\n" +
      "*Deseja mais informacoes?*\n" +
      "1\uFE0F\u20E3 Ver Entregas\n" +
      "2\uFE0F\u20E3 Ver Valores\n" +
      "4\uFE0F\u20E3 Nova Busca"
  }];
}

function formatarValor(val) {
  const n = parseFloat(String(val || "0").replace(",", ".")) || 0;
  return "R$ " + n.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

function formatarData(val) {
  if (!val) return "-";
  try {
    const d = new Date(val);
    return d.toLocaleDateString('pt-BR');
  } catch(e) {
    return String(val).substring(0, 10);
  }
}

function numeroLabel(i) {
  const emojis = [
    "1\uFE0F\u20E3","2\uFE0F\u20E3","3\uFE0F\u20E3","4\uFE0F\u20E3","5\uFE0F\u20E3",
    "6\uFE0F\u20E3","7\uFE0F\u20E3","8\uFE0F\u20E3","9\uFE0F\u20E3"
  ];
  if (i < 9) return emojis[i];
  return "*" + (i + 1) + ".*";
}

if (todos.length === 1) {
  const c = todos[0].json;
  if (!staticData.contextos[remetente]) staticData.contextos[remetente] = {};
  staticData.contextos[remetente].contratos = [c];
  return [{
    remetente,
    mensagem_retorno:
      "\uD83D\uDCDC *Contrato:* " + (c.NUMERO || "-") +
      "\n\uD83C\uDFE2 *Contratada:* " + (c.CONTRATADA || "-") +
      "\n\uD83C\uDFAF *Objeto:* " + (c.OBJETO || "-") +
      "\n\uD83D\uDFE1 *Situacao:* " + (c.SITUACAO || "-") +
      "\n\uD83D\uDCC5 *Inicio:* " + formatarData(c.DT_INICIO) +
      "\n\uD83D\uDCC5 *Fim:* " + formatarData(c.DT_FIM) +
      "\n\uD83D\uDCB0 *Total:* " + formatarValor(c.TOTAL_CONTRATADO) +
      "\n\uD83D\uDCB3 *Executado:* " + formatarValor(c.VL_EXECUTADO) +
      "\n\uD83D\uDCB3 *Pago:* " + formatarValor(c.VL_PAGO) +
      "\n\uD83D\uDCCA *Exec:* " + (c.PC_EXECUTADO || "0") + "%" +
      "\n\n*Deseja mais informacoes?*\n" +
      "1\uFE0F\u20E3 Ver Entregas\n" +
      "2\uFE0F\u20E3 Ver Valores\n" +
      "4\uFE0F\u20E3 Nova Busca"
  }];
}

const grupos = {};
const listaOrdenada = [];
todos.forEach(item => {
  const sit = item.json.SITUACAO || "Outros";
  if (!grupos[sit]) grupos[sit] = [];
  grupos[sit].push(item.json);
});

let mensagem = "\uD83D\uDCDC *Contratos do Projeto*\n*" + p.NOME + "*\n\n";
let contador = 0;

Object.keys(grupos).forEach(situacao => {
  mensagem += "\uD83D\uDFE1 *" + situacao + "*\n";
  grupos[situacao].forEach(c => {
    listaOrdenada.push(c);
    mensagem += "\n" + numeroLabel(contador) +
      " *" + (c.NUMERO || "-") + "*" +
      "\n\uD83C\uDFAF " + (c.OBJETO || "-") +
      "\n\uD83D\uDCCA *" + (c.PC_EXECUTADO || "0") + "% exec.*\n";
    contador++;
  });
  mensagem += "\n";
});

if (!staticData.contextos[remetente]) staticData.contextos[remetente] = {};
staticData.contextos[remetente].contratos = listaOrdenada;

mensagem += "\uD83D\uDC47 Digite o numero para ver detalhes\n4\uFE0F\u20E3 Nova Busca";
return [{ remetente, mensagem_retorno: mensagem }];

const input = $input.item.json;
const textoOriginal =
  input.body?.data?.message?.conversation ||
  input.body?.data?.message?.listResponseMessage?.singleSelectReply?.selectedRowId ||
  input.body?.text || "";
const textoLimpo = textoOriginal.trim();
const remetente = input.body?.data?.key?.remoteJid || "";

if (!textoLimpo || !remetente) {
  return [{ tipo: "ignorar", busca_limpa: "", remetente: "", mensagem_retorno: "" }];
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.contextos) staticData.contextos = {};

const TIMEOUT_MS = 20 * 60 * 1000;
const agora = Date.now();

let contexto = staticData.contextos[remetente] || {
  termos: [], lista: null, contratos: null,
  campos_acumulados: {}, projeto_exibido: false,
  projeto_atual: null, ultimaInteracao: null
};

if (contexto.ultimaInteracao && (agora - contexto.ultimaInteracao) > TIMEOUT_MS) {
  contexto = { termos: [], lista: null, contratos: null, campos_acumulados: {}, projeto_exibido: false, projeto_atual: null, ultimaInteracao: null };
  staticData.contextos[remetente] = contexto;
  return [{
    tipo: "saudacao", busca_limpa: "", remetente,
    mensagem_retorno: "\u23F1\uFE0F Sua sessao expirou por falta de interacao.\n\nOla! Bem-vindo ao Projeta SC \uD83C\uDFDB\uFE0F\nSou o assistente de projetos do Governo de Santa Catarina.\n\n\uD83D\uDD0E Digite o que voce deseja consultar:"
  }];
}

const textoNormalizado = textoLimpo.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-z0-9 \/]/g, "").trim();
const saudacoes = ['oi', 'ola', 'oie', 'bom dia', 'boa tarde', 'boa noite', 'hey', 'hello'];
const eSaudacao = saudacoes.some(s => textoNormalizado === s || textoNormalizado.startsWith(s + " "));
const eNumero = /^\d+$/.test(textoLimpo.trim());
const eCurto = textoLimpo.length < 4 && !eNumero;

// Detecta pergunta livre antecipadamente (tem prioridade sobre saudacao)
const palavrasInterrogativas = [
  'qual', 'quanto', 'quantos', 'quando', 'como', 'por que', 'porque',
  'quem', 'onde', 'me fala', 'me conta', 'me diz', 'explica', 'detalha', 'mostra'
];
const ePergunta = textoLimpo.includes('?') ||
  palavrasInterrogativas.some(p => textoNormalizado.startsWith(p));

// 1. SAUDACAO — apenas saudacao pura (sem pergunta embutida)
if ((eSaudacao || eCurto) && !ePergunta) {
  staticData.contextos[remetente] = { termos: [], lista: null, contratos: null, campos_acumulados: {}, projeto_exibido: false, projeto_atual: null, ultimaInteracao: agora };
  return [{ tipo: "saudacao", busca_limpa: "", remetente, mensagem_retorno: "" }];
}

// 2. RESET
if (textoNormalizado === "menu" || textoNormalizado === "0") {
  staticData.contextos[remetente] = { termos: [], lista: null, contratos: null, campos_acumulados: {}, projeto_exibido: false, projeto_atual: null, ultimaInteracao: agora };
  return [{ tipo: "saudacao", busca_limpa: "", remetente, mensagem_retorno: "" }];
}

// 3. CODIGO DE PROCESSO (ex: 654/2014)
const eCodigo = /^\d+\/\d{4}$/.test(textoLimpo.trim());
if (eCodigo) {
  contexto = { termos: [textoLimpo], lista: null, contratos: null, campos_acumulados: { codigo: textoLimpo }, projeto_exibido: false, projeto_atual: null, ultimaInteracao: agora };
  staticData.contextos[remetente] = contexto;
  return [{ tipo: "busca", busca_limpa: textoLimpo, campos_acumulados: { codigo: textoLimpo }, campos_faltantes: [], remetente, mensagem_retorno: "" }];
}

// 4. SELECAO DE ITEM DA LISTA DE PROJETOS
if (eNumero && contexto.lista && contexto.lista[parseInt(textoLimpo) - 1]) {
  const projeto = contexto.lista[parseInt(textoLimpo) - 1];
  contexto.ultimaInteracao = agora;
  contexto.lista = null;
  staticData.contextos[remetente] = contexto;
  return [{ tipo: "selecao", projeto, busca_limpa: "", remetente, mensagem_retorno: "" }];
}

// 4B. SELECAO DE CONTRATO DA LISTA
if (eNumero && contexto.contratos && contexto.contratos[parseInt(textoLimpo) - 1]) {
  const contrato = contexto.contratos[parseInt(textoLimpo) - 1];
  contexto.ultimaInteracao = agora;
  staticData.contextos[remetente] = contexto;
  return [{ tipo: "selecao_contrato", contrato, busca_limpa: "", remetente, mensagem_retorno: "" }];
}

// 5. SUBMENU DO PROJETO
if (contexto.projeto_atual) {
  if (textoLimpo === "nova_busca" || textoNormalizado === "4") {
    staticData.contextos[remetente] = { termos: [], lista: null, contratos: null, campos_acumulados: {}, projeto_exibido: false, projeto_atual: null, ultimaInteracao: agora };
    return [{ tipo: "reinicio", busca_limpa: "", remetente, mensagem_retorno: "" }];
  }
  if (textoLimpo === "entregas" || textoNormalizado === "1") {
    contexto.ultimaInteracao = agora;
    staticData.contextos[remetente] = contexto;
    return [{ tipo: "submenu", submenu: "entregas", projeto: contexto.projeto_atual, busca_limpa: "", remetente, mensagem_retorno: "" }];
  }
  if (textoLimpo === "valores" || textoNormalizado === "2") {
    contexto.ultimaInteracao = agora;
    staticData.contextos[remetente] = contexto;
    return [{ tipo: "submenu", submenu: "valores", projeto: contexto.projeto_atual, busca_limpa: "", remetente, mensagem_retorno: "" }];
  }
